'use strict';

var escapeHighlight = require('./escape-highlight.js');

function concatHighlightedParts(parts) {
    var highlightPreTag = escapeHighlight.TAG_REPLACEMENT.highlightPreTag, highlightPostTag = escapeHighlight.TAG_REPLACEMENT.highlightPostTag;
    return parts.map(function(part) {
        return part.isHighlighted ? highlightPreTag + part.value + highlightPostTag : part.value;
    }).join('');
}

exports.concatHighlightedParts = concatHighlightedParts;
